import{_ as r,r as n,o as s,c as o,a as e,d as a,e as t,b as l}from"./app.ad464663.js";const d="/assets/system-call-process.a03bd5e9.png",c="/assets/kernel-and-user-space.52325bd4.jpg",p="/assets/blocking-io.cfa18994.jpg",h="/assets/non-blocking-io.e3a51b00.jpg",u="/assets/multiplexing-io.a52d130d.jpg",O="/assets/signal-driven-io.4d07a549.jpg",I="/assets/async-io.1723e8fe.jpg",f={},_=t('<h1 id="linux\u4E0B\u76845\u79CDio\u6A21\u578B" tabindex="-1"><a class="header-anchor" href="#linux\u4E0B\u76845\u79CDio\u6A21\u578B" aria-hidden="true">#</a> Linux\u4E0B\u76845\u79CDIO\u6A21\u578B</h1><p>Linux\u4E0B\u7684IO\u4E3B\u8981\u5206\u4E3A\uFF1A\u963B\u585EIO\u3001\u975E\u963B\u585EIO\u3001\u540C\u6B65IO\u3001\u5F02\u6B65IO\u3002</p><p>\u540C\u6B65IO\uFF1A\u7528\u6237\u8FDB\u7A0B\u4E3B\u52A8\u53D1\u8D77IO\u8BF7\u6C42\uFF0C\u7CFB\u7EDF\u5185\u6838\u63A5\u6536\u8BF7\u6C42\u3002 \u5F02\u6B65IO\uFF1A\u7CFB\u7EDF\u5185\u6838\u5904\u7406\u5B8C\u6210\u540E\uFF0C\u4E3B\u52A8\u53D1\u8D77IO\u8BF7\u6C42\uFF0C\u901A\u8FC7\u56DE\u8C03\u7684\u65B9\u5F0F\u901A\u77E5\u7528\u6237\u8FDB\u7A0B\u6765\u63A5\u6536\u8BF7\u6C42\u3002 \u963B\u585EIO: \u7528\u6237\u8FDB\u7A0B\u53D1\u8D77IO\u8BF7\u6C42\u540E\uFF0C\u4F1A\u53D1\u751F\u963B\u585E\uFF0C\u76F4\u5230\u5185\u6838IO\u64CD\u4F5C\u5F7B\u5E95\u5B8C\u6210\uFF0C\u7528\u6237\u8FDB\u7A0B\u80FD\u7EE7\u7EED\u540E\u9762\u7684\u64CD\u4F5C\u3002 \u975E\u963B\u585EIO: \u7528\u6237\u8FDB\u7A0B\u53D1\u8D77IO\u8BF7\u6C42\u540E\uFF0C\u5185\u6838\u4F1A\u7ACB\u5373\u8FD4\u56DE\u72B6\u6001\u503C\uFF08\u4E0D\u5305\u542B\u6570\u636E\uFF09\uFF0C\u7528\u6237\u8FDB\u7A0B\u4E0D\u4F1A\u963B\u585E\uFF0C\u53EF\u4EE5\u7EE7\u7EED\u6267\u884C\u540E\u9762\u7684\u64CD\u4F5C\u3002</p><h2 id="\u7528\u6237\u6001\u4E0E\u5185\u6838\u6001" tabindex="-1"><a class="header-anchor" href="#\u7528\u6237\u6001\u4E0E\u5185\u6838\u6001" aria-hidden="true">#</a> \u7528\u6237\u6001\u4E0E\u5185\u6838\u6001</h2><p>\u4E3A\u4E86\u907F\u514D\u7528\u6237\u8FDB\u7A0B\u76F4\u63A5\u64CD\u4F5C\u5185\u6838\uFF0C\u4FDD\u8BC1\u5185\u6838\u5B89\u5168\uFF0C\u64CD\u4F5C\u7CFB\u7EDF\u5C06\u5185\u5B58\u5206\u4E3A\u4E24\u90E8\u5206\uFF1A\u5185\u6838\u7A7A\u95F4\u548C\u7528\u6237\u7A7A\u95F4\u3002</p><ul><li>\u5185\u6838\u6001\uFF1A\u5185\u6838\u6A21\u5757\u8FD0\u884C\u5728\u5185\u6838\u7A7A\u95F4\uFF0C\u5BF9\u5E94\u7684\u8FDB\u7A0B\u5904\u4E8E\u5185\u6838\u6001\u3002\u5185\u6838\u6A21\u5757\u5373\u662F\u64CD\u4F5C\u7CFB\u7EDF\u7684\u6838\u5FC3\uFF0C\u53EA\u6709\u5B83\u624D\u80FD\u8BBF\u95EE\u5185\u6838\u7A7A\u95F4\u548C\u786C\u4EF6\u8BBE\u5907\uFF08\u5982\uFF1A\u78C1\u76D8\u3001\u7F51\u5361\u3001\u5185\u5B58\uFF09\u3002</li><li>\u7528\u6237\u6001\uFF1A\u7528\u6237\u7A0B\u5E8F\u8FD0\u884C\u5728\u7528\u6237\u7A7A\u95F4\uFF0C\u5BF9\u5E94\u7684\u8FDB\u7A0B\u5C31\u5904\u4E8E\u7528\u6237\u6001\u3002\u8FD0\u884C\u5728\u7528\u6237\u6001\u7684\u8FDB\u7A0B\u4E0D\u80FD\u8BBF\u95EE\u5185\u6838\u7A7A\u95F4\u7684\u6570\u636E\uFF0C\u4E0D\u80FD\u8C03\u7528\u5185\u6838\u7684\u51FD\u6570\uFF0C\u4E5F\u4E0D\u80FD\u76F4\u63A5\u8BBF\u95EE\u7CFB\u7EDF\u7684\u786C\u4EF6\u8D44\u6E90\uFF0C\u9700\u8981\u5C06\u7528\u6237\u8FDB\u7A0B\u5207\u6362\u5230\u5185\u6838\u6001\u624D\u80FD\u8FDB\u884C\u7CFB\u7EDF\u8C03\u7528\u3002</li></ul><h2 id="\u5185\u6838\u7F13\u51B2\u533A\u4E0E\u8FDB\u7A0B\u7F13\u51B2\u533A" tabindex="-1"><a class="header-anchor" href="#\u5185\u6838\u7F13\u51B2\u533A\u4E0E\u8FDB\u7A0B\u7F13\u51B2\u533A" aria-hidden="true">#</a> \u5185\u6838\u7F13\u51B2\u533A\u4E0E\u8FDB\u7A0B\u7F13\u51B2\u533A</h2><p>\u5148\u8BF4\u7ED3\u8BBA\uFF0C<strong>\u7F13\u51B2\u533A\u7684\u8BBE\u8BA1\u662F\u4E3A\u4E86\u51CF\u5C11\u8BBE\u5907\u95F4\u9891\u7E41\u7684\u6570\u636E\u4EA4\u6362\u3002</strong>\u3002</p><p>\u6211\u4EEC\u90FD\u77E5\u9053\uFF0CCPU\u3001\u5185\u5B58\u548C\u5916\u90E8\u8BBE\u5907\u4E4B\u95F4\u7684\u8BFB\u5199\u901F\u5EA6\u6709\u7740\u975E\u5E38\u5927\u7684\u5DEE\u8DDD\uFF0C\u5BF9\u4E8E\u5916\u90E8\u8BBE\u5907\u7684\u8BFB\u5199\u6D89\u53CA\u64CD\u4F5C\u7CFB\u7EDF\u7684\u4E2D\u65AD\u3002\u53D1\u751F\u4E2D\u65AD\u65F6\uFF0C\u9700\u8981\u4FDD\u5B58\u8FDB\u7A0B\u7684\u6570\u636E\u548C\u72B6\u6001\u4FE1\u606F\uFF0C\u7B49\u4E2D\u65AD\u7ED3\u675F\u540E\uFF0C\u53C8\u9700\u8981\u6062\u590D\u4E4B\u524D\u7F13\u5B58\u7684\u6570\u636E\u548C\u72B6\u6001\u4FE1\u606F\u3002\u9891\u7E41\u7684\u4E2D\u65AD\u4F1A\u5E26\u6765\u5F88\u5927\u7684\u635F\u8017\uFF0C\u7F13\u51B2\u533A\u7684\u8BBE\u8BA1\u5C31\u662F\u4E3A\u4E86\u51CF\u5C11\u8FD9\u79CD\u635F\u8017\u7684\u51FA\u73B0\u3002</p><blockquote><p>\u6CE8\u610F\uFF1A\u4E2D\u65AD\u662F\u65E0\u6CD5\u907F\u514D\u7684\uFF0C\u7F13\u51B2\u533A\u7684\u8BBE\u8BA1\u4EC5\u4EC5\u662F\u4E3A\u4E86\u51CF\u5C11\u4E2D\u65AD\u6B21\u6570\u7684\u51FA\u73B0\u3002</p></blockquote><p>\u6240\u5E78\u7684\u662F\uFF0C\u64CD\u4F5C\u7CFB\u7EDF\u4F1A\u81EA\u52A8\u5BF9\u5185\u6838\u7684\u7F13\u51B2\u533A\u8FDB\u884C\u76D1\u63A7\uFF0C\u81F3\u4E8E\u4EC0\u4E48\u65F6\u5019\u51FA\u73B0\u4E2D\u65AD\uFF08\u5305\u62EC\u8BFB\u4E2D\u65AD\u3001\u5199\u4E2D\u65AD\uFF09\uFF0C\u64CD\u4F5C\u7CFB\u7EDF\u4F1A\u5E2E\u6211\u4EEC\u5904\u7406\uFF0C\u5E94\u7528\u7A0B\u5E8F\u4E0D\u7528\u5173\u5FC3\u3002</p><p>\u4EE5\u4E00\u4E2A\u5B8C\u6574\u7684\u5BA2\u6237\u7AEF\u8BF7\u6C42\u4E3A\u4F8B\u3002 <img src="'+d+`" alt="system call process"></p><div class="language-code ext-code line-numbers-mode"><pre class="language-code"><code>1. \u5BA2\u6237\u7AEF\u53D1\u9001\u8BF7\u6C42\uFF1AJava\u5BA2\u6237\u7AEF\u901A\u8FC7write\u8C03\u7528\u5C06\u6570\u636E\u590D\u5236\u5230\u5185\u6838\u7F13\u51B2\u533A\uFF0C\u518D\u5C06\u5185\u6838\u7F13\u51B2\u533A\u7684\u6570\u636E\u901A\u8FC7\u7F51\u5361\u53D1\u9001\u51FA\u53BB\u3002
2. \u670D\u52A1\u7AEF\u63A5\u6536\u8BF7\u6C42\uFF1A\u670D\u52A1\u7AEF\u901A\u8FC7read\u8C03\u7528\u5C06\u6570\u636E\u8BFB\u5165\u5185\u6838\u7F13\u51B2\u533A\uFF0C\u518D\u5C06\u6570\u636E\u590D\u5236\u5230Java\u8FDB\u7A0B\u7F13\u51B2\u533A\u3002
3. \u670D\u52A1\u7AEF\u5904\u7406\u8BF7\u6C42\uFF1AJava\u4ECE\u8FDB\u7A0B\u7F13\u51B2\u533A\u4E2D\u8BFB\u53D6\u6570\u636E\uFF0C\u5B8C\u6210\u4E1A\u52A1\u5904\u7406\u3002
4. \u670D\u52A1\u7AEF\u6570\u636E\u8FD4\u56DE\uFF1A\u4E1A\u52A1\u5904\u7406\u5B8C\u6210\u540E\uFF0C\u670D\u52A1\u7AEF\u901A\u8FC7write\u8C03\u7528\u5C06\u6570\u636E\u4ECE\u7528\u6237\u7F13\u51B2\u533A\u5199\u5165\u5185\u6838\u7F13\u51B2\u533A\uFF0C\u6700\u540E\u5C06\u6570\u636E\u901A\u8FC7\u7F51\u5361\u8FD4\u56DE\u7ED9\u5BA2\u6237\u7AEF\u3002
5. \u5BA2\u6237\u7AEF\u63A5\u6536\u6570\u636E\uFF1A\u5BA2\u6237\u7AEF\u901A\u8FC7read\u8C03\u7528\uFF0C\u5C06\u7F51\u5361\u4E2D\u7684\u6570\u636E\u8BFB\u5165\u5185\u6838\u7F13\u51B2\u533A\uFF0C\u7136\u540E\u590D\u5236\u5230\u7528\u6237\u7F13\u51B2\u533A\u3002
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>\u4E3A\u4EC0\u4E48\u8981\u8BBE\u8BA1\u7684\u8FD9\u4E48\u590D\u6742\u5462\uFF1F</p><ul><li>\u51CF\u5C11\u5F00\u53D1\u7684\u590D\u6742\u5EA6\uFF0C\u5982\u679C\u6211\u4EEC\u5199\u7684\u7A0B\u5E8F\u8981\u8BBF\u95EE\u786C\u4EF6\u8D44\u6E90\u65F6\uFF0C\u8981\u81EA\u5DF1\u53BB\u5199\u8BFB\u53D6\u786C\u76D8\u7684\u4EE3\u7801\u3001\u8BFB\u5185\u5B58\u7684\u4EE3\u7801\uFF0C\u8FD9\u65E0\u7591\u662F\u53CA\u5176\u590D\u6742\u7684\u3002</li><li>\u5B89\u5168\u6027\uFF0C\u5728\u6709\u4E9BCPU\u6307\u4EE4\u4E2D\uFF0C\u6709\u4E9B\u662F\u975E\u5E38\u5371\u9669\u7684\uFF0C\u4F1A\u76F4\u63A5\u5BFC\u81F4\u7CFB\u7EDF\u5D29\u6E83\uFF0C\u8BD5\u60F3\u4E00\u4E0B\uFF0C\u5982\u679C\u4F60\u5199\u7684\u4EE3\u7801\u6709\u4E2Abug\uFF0C\u76F4\u63A5\u5BFC\u81F4\u7CFB\u7EDF\u5D29\u6E83\u91CD\u542F\u4E86\uFF0C\u4F60\u7684\u8001\u677F\u4F1A\u662F\u4EC0\u4E48\u53CD\u5E94\uFF1F</li></ul><p>\u6709\u4E86\u4E0A\u8FF0\u57FA\u7840\u540E\uFF0C\u54B1\u4EEC\u518D\u6765\u770B\u4E00\u4E0B\u4E00\u4E2A\u67E5\u8BE2\u6570\u636E\u7684\u8BF7\u6C42\uFF0C\u901A\u5E38\u6211\u4EEC\u8FD9\u6837\u53BB\u7406\u89E3\uFF1A\u4ECE\u78C1\u76D8\u4E2D\u8BFB\u53D6\u6570\u636E\uFF0C\u7136\u540E\u52A0\u8F7D\u5230\u5185\u5B58\u4E2D\uFF0C\u6700\u540E\u518D\u5C06\u6570\u636E\u8FD4\u56DE\u3002\u5176\u5B9E\u5185\u90E8\u7ECF\u5386\u4E86\u5982\u4E0B\u66F4\u4E3A\u590D\u6742\u7684\u8FC7\u7A0B\u3002</p><ul><li>\u7528\u6237\u8FDB\u7A0B\u53D1\u8D77\u4E00\u4E2A\u7CFB\u7EDF\u8C03\u7528</li><li>\u5185\u6838\u6267\u884C\u6307\u4EE4\uFF0C\u5C06\u6570\u636E\u4ECE [\u78C1\u76D8] \u62F7\u8D1D\u5230 [\u5185\u6838buffer]</li><li>\u5C06\u6570\u636E\u4ECE [\u5185\u6838buffer] \u62F7\u8D1D\u5230 [\u7528\u6237buffer]</li><li>\u6570\u636E\u62F7\u8D1D\u5B8C\u6210\u540E\uFF0C\u8FD4\u56DE\u6570\u636E</li></ul><p>\u6700\u540E\u6211\u4EEC\u4ECE\u5185\u6838\u7A7A\u95F4\u548C\u7528\u6237\u7A7A\u95F4\u7684\u89D2\u5EA6\u770B\u4E00\u770B\u6574\u4E2A Linux \u7CFB\u7EDF\u7684\u7ED3\u6784\u3002\u5B83\u5927\u4F53\u53EF\u4EE5\u5206\u4E3A\u4E09\u4E2A\u90E8\u5206\uFF0C\u4ECE\u4E0B\u5F80\u4E0A\u4F9D\u6B21\u4E3A\uFF1A\u786C\u4EF6 -&gt; \u5185\u6838\u7A7A\u95F4 -&gt; \u7528\u6237\u7A7A\u95F4\u3002 <img src="`+c+'" alt="kernel-and-user-space"></p><ul><li>\u7CFB\u7EDF\u8C03\u7528\uFF1A\u4E3A\u4E86\u4F7F\u5E94\u7528\u7A0B\u5E8F\u8BBF\u95EE\u5230\u5185\u6838\u7684\u8D44\u6E90\uFF0C\u5982 CPU\u3001\u5185\u5B58\u3001I/O\uFF0C\u5185\u6838\u5FC5\u987B\u63D0\u4F9B\u4E00\u7EC4\u901A\u7528\u7684\u8BBF\u95EE\u63A5\u53E3\uFF0C\u8FD9\u4E9B\u63A5\u53E3\u5C31\u53EB\u7CFB\u7EDF\u8C03\u7528\u3002</li><li>\u5E93\u51FD\u6570\uFF1A\u5C4F\u853D\u8FD9\u4E9B\u590D\u6742\u7684\u5E95\u5C42\u5B9E\u73B0\u7EC6\u8282\uFF0C\u51CF\u8F7B\u7A0B\u5E8F\u5458\u7684\u8D1F\u62C5\uFF0C\u4ECE\u800C\u66F4\u52A0\u5173\u6CE8\u4E0A\u5C42\u7684\u903B\u8F91\u5B9E\u73B0\uFF0C\u5B83\u5BF9\u7CFB\u7EDF\u8C03\u7528\u8FDB\u884C\u5C01\u88C5\uFF0C\u63D0\u4F9B\u7B80\u5355\u7684\u57FA\u672C\u63A5\u53E3\u7ED9\u7A0B\u5E8F\u5458\u3002</li><li>shell\uFF1A\u987E\u540D\u601D\u4E49\uFF0C\u5C31\u662F\u5916\u58F3\u7684\u610F\u601D\uFF0C\u5C31\u597D\u50CF\u628A\u5185\u6838\u5305\u88F9\u8D77\u6765\u7684\u5916\u58F3\uFF0C\u5B83\u662F\u4E00\u79CD\u7279\u6B8A\u7684\u5E94\u7528\u7A0B\u5E8F\uFF0C\u4FD7\u79F0\u547D\u4EE4\u884C\u3002Shell \u4E5F\u662F\u53EF\u7F16\u7A0B\u7684\uFF0C\u5B83\u6709\u6807\u51C6\u7684 Shell \u8BED\u6CD5\uFF0C\u7B26\u5408\u5176\u8BED\u6CD5\u7684\u6587\u672C\u53EB Shell \u811A\u672C\uFF0C\u5F88\u591A\u4EBA\u90FD\u4F1A\u7528 Shell \u811A\u672C\u5B9E\u73B0\u4E00\u4E9B\u5E38\u7528\u7684\u529F\u80FD\uFF0C\u53EF\u4EE5\u63D0\u9AD8\u5DE5\u4F5C\u6548\u7387\u3002</li></ul><h2 id="\u7528\u6237\u6001\u4E0E\u5185\u6838\u6001\u7684\u5207\u6362" tabindex="-1"><a class="header-anchor" href="#\u7528\u6237\u6001\u4E0E\u5185\u6838\u6001\u7684\u5207\u6362" aria-hidden="true">#</a> \u7528\u6237\u6001\u4E0E\u5185\u6838\u6001\u7684\u5207\u6362</h2><p>\u6709\u4E09\u79CD\u60C5\u51B5\u4F1A\u5BFC\u81F4\u4ECE\u7528\u6237\u6001\u5207\u6362\u5230\u5185\u6838\u6001\uFF1A</p><ul><li>\u7CFB\u7EDF\u8C03\u7528\uFF1A\u7528\u6237\u6001\u8FDB\u7A0B\u4E3B\u52A8\u5207\u6362\u5230\u5185\u6838\u6001\u7684\u65B9\u5F0F\uFF0C\u7528\u6237\u6001\u8FDB\u7A0B\u901A\u8FC7\u7CFB\u7EDF\u8C03\u7528\u5411\u64CD\u4F5C\u7CFB\u7EDF\u7533\u8BF7\u8D44\u6E90\u5B8C\u6210\u5DE5\u4F5C\uFF0C\u4F8B\u5982 fork\uFF08\uFF09\u5C31\u662F\u4E00\u4E2A\u521B\u5EFA\u65B0\u8FDB\u7A0B\u7684\u7CFB\u7EDF\u8C03\u7528\uFF0C\u7CFB\u7EDF\u8C03\u7528\u7684\u673A\u5236\u6838\u5FC3\u4F7F\u7528\u4E86\u64CD\u4F5C\u7CFB\u7EDF\u4E3A\u7528\u6237\u7279\u522B\u5F00\u653E\u7684\u4E00\u4E2A\u4E2D\u65AD\u6765\u5B9E\u73B0\uFF0C\u5982 Linux \u7684 int 80h \u4E2D\u65AD\uFF0C\u4E5F\u53EF\u4EE5\u79F0\u4E3A\u8F6F\u4E2D\u65AD</li><li>\u5F02\u5E38\uFF1A\u5F53 C P U \u5728\u6267\u884C\u7528\u6237\u6001\u7684\u8FDB\u7A0B\u65F6\uFF0C\u53D1\u751F\u4E86\u4E00\u4E9B\u6CA1\u6709\u9884\u77E5\u7684\u5F02\u5E38\uFF0C\u8FD9\u65F6\u5F53\u524D\u8FD0\u884C\u8FDB\u7A0B\u4F1A\u5207\u6362\u5230\u5904\u7406\u6B64\u5F02\u5E38\u7684\u5185\u6838\u76F8\u5173\u8FDB\u7A0B\u4E2D\uFF0C\u4E5F\u5C31\u662F\u5207\u6362\u5230\u4E86\u5185\u6838\u6001\uFF0C\u5982\u7F3A\u9875\u5F02\u5E38</li><li>\u4E2D\u65AD\uFF1A\u5F53 C P U \u5728\u6267\u884C\u7528\u6237\u6001\u7684\u8FDB\u7A0B\u65F6\uFF0C\u5916\u56F4\u8BBE\u5907\u5B8C\u6210\u7528\u6237\u8BF7\u6C42\u7684\u64CD\u4F5C\u540E\uFF0C\u4F1A\u5411 C P U \u53D1\u51FA\u76F8\u5E94\u7684\u4E2D\u65AD\u4FE1\u53F7\uFF0C\u8FD9\u65F6 C P U \u4F1A\u6682\u505C\u6267\u884C\u4E0B\u4E00\u6761\u5373\u5C06\u8981\u6267\u884C\u7684\u6307\u4EE4\uFF0C\u8F6C\u5230\u4E0E\u4E2D\u65AD\u4FE1\u53F7\u5BF9\u5E94\u7684\u5904\u7406\u7A0B\u5E8F\u53BB\u6267\u884C\uFF0C\u4E5F\u5C31\u662F\u5207\u6362\u5230\u4E86\u5185\u6838\u6001\u3002\u5982\u786C\u76D8\u8BFB\u5199\u64CD\u4F5C\u5B8C\u6210\uFF0C\u7CFB\u7EDF\u4F1A\u5207\u6362\u5230\u786C\u76D8\u8BFB\u5199\u7684\u4E2D\u65AD\u5904\u7406\u7A0B\u5E8F\u4E2D\u6267\u884C\u540E\u8FB9\u7684\u64CD\u4F5C\u7B49\u3002</li></ul><h2 id="_5\u79CDio\u6A21\u578B" tabindex="-1"><a class="header-anchor" href="#_5\u79CDio\u6A21\u578B" aria-hidden="true">#</a> 5\u79CDIO\u6A21\u578B</h2><h3 id="\u540C\u6B65\u963B\u585Eio" tabindex="-1"><a class="header-anchor" href="#\u540C\u6B65\u963B\u585Eio" aria-hidden="true">#</a> \u540C\u6B65\u963B\u585EIO</h3><p>\u5E94\u7528\u7A0B\u5E8F\u53D1\u8D77\u4E00\u4E2AIO\u8C03\u7528\uFF0C\u7136\u540E\u5C31\u8FDB\u5165\u963B\u585E\u72B6\u6001\uFF0C\u7B49\u5F85\u6570\u636E\u51C6\u5907\u597D\uFF0C\u5F53\u5185\u6838\u51C6\u5907\u597D\u6570\u636E\u540E\uFF0C\u518D\u5C06\u6570\u636E\u62F7\u8D1D\u5230\u7528\u6237\u7A7A\u95F4\uFF0C\u6700\u540E\u8FD4\u56DE\u6210\u529F\u7684\u63D0\u793A\u3002\u5176\u7279\u70B9\u662F\u6574\u4E2A\u8FC7\u7A0B\u5B8C\u5168\u963B\u585E\uFF0C\u4E0D\u80FD\u8FDB\u884C\u5176\u4ED6\u64CD\u4F5C\u3002 <img src="'+p+'" alt="blocking io"></p><h3 id="\u540C\u6B65\u975E\u963B\u585Eio" tabindex="-1"><a class="header-anchor" href="#\u540C\u6B65\u975E\u963B\u585Eio" aria-hidden="true">#</a> \u540C\u6B65\u975E\u963B\u585EIO</h3><p>\u5E94\u7528\u7A0B\u5E8F\u53D1\u8D77\u4E00\u4E2AIO\u8C03\u7528\u540E\uFF0C\u5185\u6838\u7ACB\u5373\u8FD4\u56DE\u4E00\u4E2A\u7ED3\u679C\uFF0Cy\u6B64\u65F6\u5E94\u7528\u7A0B\u5E8F\u4E0D\u4F1A\u963B\u585E\uFF0C\u800C\u662F\u7EE7\u7EED\u6267\u884C\u3002\u90A3\u5982\u4F55\u77E5\u9053\u6570\u636E\u51C6\u5907\u597D\u4E86\u5462\uFF1F\u5F88\u7B80\u5355\uFF0C\u5E94\u7528\u7A0B\u5E8F\u5C06\u6301\u7EED\u8F6E\u8BE2\uFF0C\u76F4\u5230\u6570\u636E\u51C6\u5907\u597D\uFF0C\u5728\u8F6E\u8BE2\u7684\u95F4\u9699\uFF0C\u5E94\u7528\u7A0B\u5E8F\u5C31\u53EF\u4EE5\u4F5C\u5176\u4ED6\u4E8B\u60C5\u4E86\u3002\u7136\u540E\u6574\u4E2A\u8F6E\u8BE2\u7684 \u8FC7\u7A0B\u5C06\u5360\u7528\u5927\u91CF\u7684CPU\u3002 <img src="'+h+'" alt="non-blocking io"></p><h3 id="io\u591A\u8DEF\u590D\u7528" tabindex="-1"><a class="header-anchor" href="#io\u591A\u8DEF\u590D\u7528" aria-hidden="true">#</a> IO\u591A\u8DEF\u590D\u7528</h3><p>\u975E\u963B\u585E I/O \u6A21\u578B\u6709\u4E00\u4E2A\u7279\u70B9\u5C31\u662F\u7528\u6237\u8FDB\u7A0B\u9700\u8981\u4E0D\u65AD\u5730\u4E3B\u52A8\u8F6E\u8BE2kernel\u6570\u636E\u662F\u5426\u51C6\u5907\u597D\uFF0C\u8FD9\u6837\u7684\u64CD\u4F5C\u5BFC\u81F4CPU\u7684\u5360\u7528\u7387\u5F88\u9AD8\u3002\u5982\u4F55\u89C4\u907F\u8FD9\u4E00\u4E2A\u95EE\u9898\u5462\uFF1F\u5185\u6838\u7ED9\u51FA\u4E86\u4E00\u4E2A\u89E3\u51B3\u529E\u6CD5\uFF0C\u5C31\u662F I/O \u591A\u8DEF\u590D\u7528\u3002</p><p>\u4F46\u662F\u4F60\u4F1A\u53D1\u73B0\uFF0C\u5185\u6838\u4E5F\u662F\u901A\u8FC7\u8F6E\u8BE2\u7684\u65B9\u5F0F\u76D1\u63A7 I/O \u901A\u9053\u63A5\u53E3\u662F\u5426\u51C6\u5907\u597D\u6570\u636E\uFF0C\u90A3\u4E48\u548C\u7528\u6237\u8F6E\u8BE2\u6709\u4EC0\u4E48\u533A\u522B\u5462\uFF1F</p><p>\u5185\u6838\u4E0D\u518D\u53EA\u76D1\u63A7\u4E00\u4E2A I/O \u901A\u9053\uFF0C\u800C\u662F\u591A\u4E2A\u3002\u548C\u5185\u6838\u76F8\u6BD4\uFF0C\u7528\u6237\u8FDB\u7A0B\u53EA\u9700\u8981\u5173\u6CE8\u81EA\u5DF1\u60F3\u8981\u8BFB\u5199\u6570\u636E\u7684 I/O \u901A\u9053\u5373\u53EF\uFF0C\u81F3\u4E8E\u7CFB\u7EDF\u4E2D\u5176\u4ED6\u7684 I/O \u901A\u9053\u5219\u4E0D\u5173\u5FC3\u3002\u5C06\u8F6E\u8BE2\u8F6C\u79FB\u5230\u5185\u6838\u80FD\u51CF\u5C11\u7528\u6237\u8FDB\u7A0B\u5BF9CPU\u7684\u5360\u7528\u7387\u3002</p><p>\u4E3B\u6D41\u4E2D\u95F4\u4EF6netty\u3001redis\u3001nginx\u90FD\u5E94\u7528\u4E86\u8BE5\u6A21\u578B\uFF0C\u53EF\u89C1\u8BE5\u6A21\u578B\u662F\u591A\u4E48\u6210\u529F\u3002</p><blockquote><p>\u6CE8\u610F\uFF1AIO\u591A\u8DEF\u590D\u7528\u5E76\u4E0D\u662F\u975E\u963B\u585E\u7684\uFF0C\u5B83\u53EA\u662F\u5728\u670D\u52A1\u7AEF\u901A\u8FC7\u4E00\u4E2A\u7EBF\u7A0B\u53BB\u8F6E\u8BE2\u591A\u4E2A\u8BF7\u6C42\u7684\u72B6\u6001\uFF0C\u7528\u6237\u8FDB\u7A0B\u5728\u83B7\u5F97\u7ED3\u679C\u524D\u4ECD\u7136\u662F\u963B\u585E\u7684\u3002 \u53EF\u4EE5\u8FD9\u4E48\u53BB\u7406\u89E3\uFF1A\u670D\u52A1\u7AEF\u590D\u7528\u4E86\u4E00\u4E2A\u7EBF\u7A0B\u53BB\u5904\u7406\u591A\u4E2A\u7F51\u7EDC\u8BF7\u6C42\uFF0C\u8FBE\u5230\u4E86\u591A\u8DEF\u590D\u7528\u7684\u76EE\u7684\u3002</p></blockquote><p>\u5185\u6838\u5982\u4F55\u5B9E\u73B0 I/O \u591A\u8DEF\u590D\u7528\u5462\uFF1F\u6709\u4E0B\u9762\u4E09\u79CD\u65B9\u5F0F\u3002</p><h3 id="select" tabindex="-1"><a class="header-anchor" href="#select" aria-hidden="true">#</a> select</h3><p>Linux\u63D0\u4F9B\u4E86select\uFF0C\u8FDB\u7A0B\u901A\u8FC7\u5C06\u4E00\u4E2A\u6216\u591A\u4E2Afd\u4F20\u9012\u7ED9select\u6216poll\u7CFB\u7EDF\u8C03\u7528\uFF0C\u963B\u585E\u5728select\u64CD\u4F5C\u4E0A\uFF0C\u8FD9\u6837select\u53EF\u4EE5\u5E2E\u6211\u4EEC\u4FA6\u6D4B\u591A\u4E2Afd\u662F\u5426\u5904\u4E8E\u5C31\u7EEA\u72B6\u6001\u3002 \u65F6\u95F4\u590D\u6742\u5EA6 O(n)\u3002\u56E0\u4E3A select\u662F\u987A\u5E8F\u626B\u63CFfd\u662F\u5426\u5C31\u7EEA\uFF0C\u53EA\u80FD\u65E0\u5DEE\u522B\u8F6E\u8BE2\u6240\u6709\u6D41\uFF0C\u800C\u4E14\u652F\u6301\u7684fd\u6570\u91CF\u6709\u9650\uFF081024\u4E2A\uFF09\uFF0C\u56E0\u6B64\u5B83\u7684\u4F7F\u7528\u53D7\u5230\u4E86\u4E00\u4E9B\u5236\u7EA6\u3002</p><h3 id="poll" tabindex="-1"><a class="header-anchor" href="#poll" aria-hidden="true">#</a> poll</h3><p>\u65F6\u95F4\u590D\u6742\u5EA6\u540C\u6837\u662F O(n) \u548C select \u7684\u533A\u522B\u662F\u5B83\u8F6E\u8BE2 I/O \u901A\u9053\u7684\u6570\u91CF\u6CA1\u6709\u9650\u5236\u3002</p><h3 id="epoll" tabindex="-1"><a class="header-anchor" href="#epoll" aria-hidden="true">#</a> epoll</h3><p>\u65F6\u95F4\u590D\u6742\u5EA6O(1)\u3002epoll\u4E0D\u518D\u901A\u8FC7\u8F6E\u8BE2\u7684\u65B9\u5F0F\u68C0\u67E5\u6BCF\u4E2AI/O\u901A\u9053\u662F\u5426\u5DF2\u7ECF\u51C6\u5907\u597D\u6570\u636E\uFF0C\u800C\u662F\u901A\u8FC7\u4E8B\u4EF6\u7684\u65B9\u5F0F\uFF0C\u4E5F\u5C31\u662F\u6BCF\u4E2AI/O\u901A\u9053\u51C6\u5907\u597D\u6570\u636E\u4E4B\u540E\u4F1A\u901A\u8FC7\u56DE\u8C03\u51FD\u6570\u901A\u77E5epoll\u6570\u636E\u5DF2\u7ECF\u51C6\u5907\u597D\uFF0C\u8FD9\u6837epoll\u7684\u65F6\u95F4\u590D\u6742\u5EA6\u5C31\u662FO(1)\uFF0C\u800C\u4E0D\u518D\u662FO(n)\u3002\u7136\u540Eepoll\u518D\u901A\u77E5\u7528\u6237\u8FDB\u7A0B\u6570\u636E\u5DF2\u7ECF\u51C6\u5907\u597D\u4E86\u3002 \u60F3\u8981epoll\u5E2E\u52A9\u7528\u6237\u8FDB\u7A0B\u76D1\u63A7I/O\u901A\u9053\uFF0C\u90A3\u4E48\u7528\u6237\u8FDB\u7A0B\u9700\u8981\u5230epoll\u4E0A\u8FDB\u884C\u6CE8\u518C\u3002</p><p><img src="'+u+'" alt="multiplexing io"></p><h3 id="\u4FE1\u53F7\u9A71\u52A8io" tabindex="-1"><a class="header-anchor" href="#\u4FE1\u53F7\u9A71\u52A8io" aria-hidden="true">#</a> \u4FE1\u53F7\u9A71\u52A8IO</h3><p>\u9996\u5148\u8BF4\u660E\u4FE1\u53F7\u9A71\u52A8I/O\u6A21\u578B\u662F\u786E\u786E\u5B9E\u5B9E\u7684\u975E\u963B\u585EI/O\u6A21\u578B\u3002</p><p>\u524D\u9762\u7684\u975E\u963B\u585EI/O\u6A21\u578B\u4F7F\u5F97\u7528\u6237\u8FDB\u7A0B\u4E0D\u963B\u585E\u7684\u5B9E\u73B0\u65B9\u6CD5\u662F\u901A\u8FC7\u8F6E\u8BE2\u7684\u65B9\u5F0F\u770B\u5185\u6838\u662F\u5426\u51C6\u5907\u597D\u6570\u636E\uFF0C\u4F46\u662F\u5728\u4FE1\u53F7\u9A71\u52A8 I/O\u6A21\u578B\u4E2D\uFF0C\u4F7F\u7528\u4FE1\u53F7\u673A\u5236\u5B9E\u73B0\uFF0C\u800C\u4E0D\u518D\u8F6E\u8BE2\u3002\u8FD9\u4F7F\u5F97\u9636\u6BB5\u4E00\u7528\u6237\u8FDB\u7A0B\u7B49\u5F85\u6570\u636E\u7684\u65F6\u5019\u786E\u5B9E\u4E0D\u963B\u585E\u4E86\u3002</p><p>\u90A3\u4E48\u4FE1\u53F7\u9A71\u52A8 I/O \u6A21\u578B\u5982\u4F55\u4FDD\u8BC1\u7528\u6237\u8FDB\u7A0B\u4E0D\u963B\u585E\u5462\uFF1F</p><p>\u7B2C\u4E00\u9636\u6BB5\uFF1A\u5E94\u7528\u8FDB\u7A0B\u662F\u8C03\u7528\u64CD\u4F5C\u7CFB\u7EDF\u5185\u6838\u63D0\u4F9B\u7684signal\u4FE1\u53F7\u5904\u7406\u63A5\u53E3\uFF0C\u4F46\u662F\u8BE5\u63A5\u53E3\u4E0D\u4F1A\u9020\u6210\u963B\u585E\u800C\u662F\u7ACB\u5373\u8FD4\u56DE\u3002\u5F53\u6570\u636E\u51C6\u5907\u597D\u4E86\u4E4B\u540E\u5185\u6838\u5219\u518D\u8FD4\u56DE\u4E00\u4E2A\u4FE1\u53F7\uFF0C\u544A\u8BC9\u5E94\u7528\u7A0B\u5E8F\u3002 \u7B2C\u4E8C\u9636\u6BB5\uFF1A\u548C\u524D\u9762\u4E09\u79CD\u6A21\u578B\u5B8C\u5168\u4E00\u6837\uFF0C\u5E94\u7528\u8FDB\u7A0B\u4ECD\u7136\u4F1A\u963B\u585E\u77E5\u9053\u6570\u636E\u590D\u5236\u5B8C\u6BD5\u3002 <img src="'+O+'" alt="signal-driven io"></p><h3 id="\u5F02\u6B65io" tabindex="-1"><a class="header-anchor" href="#\u5F02\u6B65io" aria-hidden="true">#</a> \u5F02\u6B65IO</h3><p>\u524D\u56DB\u79CD\u6A21\u578B\u7684\u540C\u8D28\u662F\u7B2C\u4E8C\u9636\u6BB5\uFF0C\u5728\u5185\u6838\u5C06\u6570\u636E\u51C6\u5907\u597D\u4E4B\u540E\uFF0C\u901A\u77E5\u7528\u6237\u8FDB\u7A0B\u8C03\u7528\u7CFB\u7EDF\u7684recvfrom\u65B9\u6CD5\u5B8C\u6210\u6570\u636E\u4ECE\u5185\u6838\u7F13\u51B2\u533A\u5230\u8FDB\u7A0B\u7684\u62F7\u8D1D\uFF0C\u8FD9\u65F6\u7528\u6237\u8FDB\u7A0B\u4ECD\u65E7\u88AB\u963B\u585E\u3002\u56E0\u4E3A\u6570\u636E\u7684\u62F7\u8D1D\u662F\u7531\u7528\u6237\u8FDB\u7A0B\u5B8C\u6210\uFF0C\u6240\u4EE5\u524D\u56DB\u79CD I/O \u6A21\u578B\u90FD\u662F\u540C\u6B65 I/O\u3002</p><p>\u4F46\u662F\u5982\u679C\u6570\u636E\u7684\u62F7\u8D1D\u5DE5\u4F5C\u7531\u5185\u6838\u5B8C\u6210\uFF0C\u90A3\u4E48\u8FD9\u5C31\u662F\u4E00\u4E2A\u5F02\u6B65 I/O\u3002\u987A\u7740\u4FE1\u53F7\u9A71\u52A8\u6A21IO\u6A21\u578B\uFF0C\u5C06\u4FE1\u53F7\u901A\u77E5\u7684\u65F6\u673A\u653E\u5230\u6570\u636E\u590D\u5236\u5B8C\u6210\u4E4B\u540E\uFF0C\u5C31\u662F\u5F02\u6B65IO\u6A21\u578B\uFF0C\u8FD9\u6837\u4ECE\u6574\u4F53\u4E0A\u6765\u770B\uFF0C\u5E94\u7528\u8FDB\u7A0B\u4ECE\u6765\u6CA1\u6709\u963B\u585E\u8FC7\uFF0C\u800C\u662F\u4E00\u76F4\u8FD0\u884C\uFF0C\u76F4\u5230\u88AB\u901A\u77E5\u6570\u636E\u5DF2\u7ECF\u88AB\u590D\u5236\u5230\u81EA\u5DF1\u7684\u7A7A\u95F4\u4E2D\u4E86\u3002</p><p>\u8FD9\u79CD\u6A21\u578B\u4E0E\u4FE1\u53F7\u9A71\u52A8\u6A21\u578B\u7684\u4E3B\u8981\u533A\u522B\u662F\uFF1A\u4FE1\u53F7\u9A71\u52A8\u6A21\u578B\u7531\u5185\u6838\u901A\u77E5\u6211\u4EEC\u4F55\u65F6\u53EF\u4EE5\u5F00\u59CB\u4E00\u4E2AIO\u64CD\u4F5C\uFF1B\u5F02\u6B65IO\u6A21\u578B\u7531\u5185\u6838\u901A\u77E5\u6211\u4EECIO\u64CD\u4F5C\u4F55\u65F6\u5B8C\u6210\u3002 <img src="'+I+'" alt="async io"></p><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><p>\u53EA\u6709\u5F02\u6B65IO\u624D\u80FD\u771F\u6B63\u7B97\u5F97\u4E0A\u662F\u5F02\u6B65IO\u6A21\u578B\uFF0C\u5269\u4E0B\u76844\u4E2D\u90FD\u662F\u540C\u6B65I/O\u6A21\u578B\uFF1A</p><ul><li>\u963B\u585E I/O \u6A21\u578B</li><li>\u975E\u963B\u585E I/O \u6A21\u578B</li><li>IO \u591A\u8DEF\u590D\u7528\u6A21\u578B</li><li>\u4FE1\u53F7\u9A71\u52A8 I/O \u6A21\u578B</li></ul><p>\u8FD94\u79CD\u90FD\u662F\u540C\u6B65\u6A21\u578B\uFF0C\u5B83\u4EEC\u7684\u4E3B\u8981\u533A\u522B\u5728\u7B2C\u4E00\u9636\u6BB5\uFF0C\u6BCF\u4E2A\u6A21\u578B\u4E2D\u5E94\u7528\u8FDB\u7A0B\u963B\u585E\u7684\u5B9E\u73B0\u548C\u65B9\u5F0F\u4E0D\u540C\uFF0C\u800C\u5728\u7B2C\u4E8C\u4E2A\u9636\u6BB5\u5219\u5168\u90E8\u76F8\u540C\uFF0C\u90FD\u4F1A\u963B\u585E\u4E8E\u5185\u6838\u590D\u5236\u6570\u636E\u8FC7\u7A0B\u3002\u6240\u4EE5\u4E0D\u7BA1\u963B\u585E\u548C\u8FD8\u662F\u4E0D\u963B\u585E\u90FD\u662F\u540C\u6B65\u6A21\u578B\u3002\u5B83\u4EEC\u7684\u533A\u522B\u662F\u5728\u51C6\u5907\u6570\u636E\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u5E94\u7528\u8FDB\u7A0B\u662F\u4E0D\u662F\u963B\u585E\u3002</p><h2 id="\u53C2\u8003" tabindex="-1"><a class="header-anchor" href="#\u53C2\u8003" aria-hidden="true">#</a> \u53C2\u8003</h2>',55),b={href:"https://xie.infoq.cn/article/25df22c38dc0e925879ce4e9b",target:"_blank",rel:"noopener noreferrer"},m=l("\u7406\u89E3\u7528\u6237\u6001\u548C\u5185\u6838\u6001"),g={href:"https://xie.infoq.cn/article/df9d5150f408e600e4dedcadb",target:"_blank",rel:"noopener noreferrer"},x=l("Linux\u76845\u79CDIO\u6A21\u578B"),v={href:"https://www.cnblogs.com/supportmyself/p/14978168.html",target:"_blank",rel:"noopener noreferrer"},k=l("Linux\u7684IO\u6A21\u578B");function C(P,U){const i=n("ExternalLinkIcon");return s(),o("div",null,[_,e("ol",null,[e("li",null,[e("a",b,[m,a(i)])]),e("li",null,[e("a",g,[x,a(i)])]),e("li",null,[e("a",v,[k,a(i)])])])])}const y=r(f,[["render",C],["__file","io-pattern.html.vue"]]);export{y as default};
